export enum EligibilityStatus {
  ELIGIBLE = 'ELIGIBLE',
  INELIGIBLE = 'INELIGIBLE',
  ON_THE_FENCE = 'ON_THE_FENCE',
  UNCLEAR = 'UNCLEAR'
}

export interface AnalysisResult {
  status: EligibilityStatus;
  reasoning: string;
  recommendations: string[];
  itemName?: string;
  estimatedCost?: string;
  isReceiptDetected: boolean;
}

export interface AnalysisState {
  isAnalyzing: boolean;
  result: AnalysisResult | null;
  error: string | null;
}

import { GoogleGenAI, Type } from "@google/genai";
import { SYSTEM_PROMPT } from "../constants";
import { AnalysisResult } from "../types";

export const analyzeBikePurchase = async (
  input: string | { data: string; mimeType: string }
): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const contents: any[] = [];

  if (typeof input === 'string') {
    contents.push({ text: `Analyze this product or description: ${input}` });
  } else {
    contents.push({
      inlineData: input
    });
    contents.push({ text: "Analyze this image. Is it a bike part, accessory, or receipt? Determine eligibility." });
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: { parts: contents },
      config: {
        systemInstruction: SYSTEM_PROMPT,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            status: { type: Type.STRING },
            itemName: { type: Type.STRING },
            reasoning: { type: Type.STRING },
            recommendations: {
              type: Type.ARRAY,
              items: { type: Type.STRING }
            },
            isReceiptDetected: { type: Type.BOOLEAN },
            estimatedCost: { type: Type.STRING }
          },
          required: ["status", "reasoning", "recommendations", "isReceiptDetected"]
        }
      },
    });

    const text = response.text;
    if (!text) throw new Error("Empty response from AI");

    return JSON.parse(text) as AnalysisResult;
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    throw new Error("Failed to analyze the item. Please try again.");
  }
};

