import React from 'react';
import { AnalysisResult, EligibilityStatus } from '../types';

interface ResultDisplayProps {
  result: AnalysisResult;
  onReset: () => void;
}

const ResultDisplay: React.FC<ResultDisplayProps> = ({ result, onReset }) => {
  const getStatusConfig = (status: EligibilityStatus) => {
    switch (status) {
      case EligibilityStatus.ELIGIBLE:
        return {
          icon: 'fa-check-circle',
          color: 'text-green-600',
          bg: 'bg-green-50',
          border: 'border-green-200',
          label: 'Likely Eligible'
        };
      case EligibilityStatus.INELIGIBLE:
        return {
          icon: 'fa-times-circle',
          color: 'text-red-600',
          bg: 'bg-red-50',
          border: 'border-red-200',
          label: 'Likely Ineligible'
        };
      case EligibilityStatus.ON_THE_FENCE:
      case EligibilityStatus.UNCLEAR:
      default:
        return {
          icon: 'fa-exclamation-triangle',
          color: 'text-amber-600',
          bg: 'bg-amber-50',
          border: 'border-amber-200',
          label: 'Manual Review Recommended'
        };
    }
  };

  const config = getStatusConfig(result.status);
  const showContactButton = result.status === EligibilityStatus.ON_THE_FENCE || result.status === EligibilityStatus.UNCLEAR;

  const mailtoLink = `mailto:commuterchoice@harvard.edu?subject=Eligibility Inquiry: ${result.itemName || 'Bike Item'}&body=Hi CommuterChoice Team,%0D%0A%0D%0AI would like to verify if the following item is eligible for the Bike Commuter Benefit:%0D%0A%0D%0AItem: ${result.itemName || 'Not specified'}%0D%0ACost: ${result.estimatedCost || 'Not specified'}%0D%0A%0D%0AThank you!`;

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className={`p-6 rounded-xl border-2 ${config.bg} ${config.border} flex flex-col items-center text-center`}>
        <i className={`fas ${config.icon} text-5xl ${config.color} mb-4`}></i>
        <h2 className={`text-2xl font-bold ${config.color}`}>{config.label}</h2>
        {result.itemName && <p className="text-gray-700 font-medium mt-1">"{result.itemName}"</p>}
      </div>

      <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
        <h3 className="text-sm font-semibold text-gray-400 uppercase tracking-wider mb-3">Analysis Details</h3>
        <p className="text-gray-800 leading-relaxed mb-6">
          {result.reasoning}
        </p>

        <h3 className="text-sm font-semibold text-gray-400 uppercase tracking-wider mb-3">Next Steps</h3>
        <ul className="space-y-2">
          {result.recommendations.map((rec, i) => (
            <li key={i} className="flex items-start">
              <span className="flex-shrink-0 w-5 h-5 bg-blue-100 text-blue-600 rounded-full flex items-center justify-center text-xs font-bold mr-3 mt-0.5">
                {i + 1}
              </span>
              <span className="text-gray-700 text-sm">{rec}</span>
            </li>
          ))}
        </ul>
      </div>

      <div className="flex flex-col sm:flex-row gap-3">
        {showContactButton && (
          <a
            href={mailtoLink}
            className="flex-1 bg-amber-600 hover:bg-amber-700 text-white font-semibold py-3 px-6 rounded-xl text-center transition-all shadow-md flex items-center justify-center"
          >
            <i className="fas fa-paper-plane mr-2"></i> Submit Ticket to Staff
