import React, { useState, useRef } from 'react';
import Header from './components/Header';
import ResultDisplay from './components/ResultDisplay';
import { analyzeBikePurchase } from './services/geminiService';
import { AnalysisState } from './types';
import { HARVARD_CRIMSON } from './constants';

const App: React.FC = () => {
  const [state, setState] = useState<AnalysisState>({
    isAnalyzing: false,
    result: null,
    error: null,
  });
  const [inputText, setInputText] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setState({ ...state, isAnalyzing: true, error: null });

    try {
      const reader = new FileReader();
      reader.onload = async (e) => {
        const base64Data = e.target?.result?.toString().split(',')[1];
        if (base64Data) {
          const result = await analyzeBikePurchase({
            data: base64Data,
            mimeType: file.type,
          });
          setState({ isAnalyzing: false, result, error: null });
        }
      };
      reader.readAsDataURL(file);
    } catch (err) {
      setState({ isAnalyzing: false, result: null, error: 'Failed to process image. Please try again.' });
    }
  };

  const handleTextSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputText.trim()) return;

    setState({ ...state, isAnalyzing: true, error: null });

    try {
      const result = await analyzeBikePurchase(inputText);
      setState({ isAnalyzing: false, result, error: null });
    } catch (err) {
      setState({ isAnalyzing: false, result: null, error: 'Failed to analyze text. Please try again.' });
    }
  };

  const resetAnalysis = () => {
    setState({ isAnalyzing: false, result: null, error: null });
    setInputText('');
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col">
      <Header />

      <main className="flex-grow max-w-2xl mx-auto w-full px-4 py-8 md:py-12">
        <div className="text-center mb-10">
          <h2 className="text-3xl font-extrabold text-gray-900 mb-3 tracking-tight">
            Verify Your Bike Purchase
          </h2>
          <p className="text-gray-600 max-w-md mx-auto">
            Upload a receipt, take a photo of an item, or describe a product to check if it's eligible for the Harvard Bike Commuter Benefit.
          </p>
        </div>

        {!state.result && !state.isAnalyzing && (
          <div className="space-y-8 animate-in fade-in duration-500">
            {/* Image Upload Area */}
            <div 
              onClick={() => fileInputRef.current?.click()}
              className="bg-white border-2 border-dashed border-gray-300 rounded-2xl p-10 flex flex-col items-center justify-center cursor-pointer hover:border-red-400 hover:bg-red-50 transition-all group"
            >
              <div className="w-16 h-16 bg-gray-100 rounded-full flex items-center justify-center mb-4 group-hover:bg-red-100 transition-colors">
                <i className="fas fa-camera text-2xl text-gray-500 group-hover:text-red-600"></i>
              </div>
              <p className="text-lg font-semibold text-gray-800">Upload Image or Receipt</p>
              <p className="text-sm text-gray-500 mt-1">Tap to browse or take a photo</p>
              <input 
                type="file" 
                ref={fileInputRef} 
                onChange={handleFileUpload} 
                className="hidden" 
                accept="image/*"
              />
            </div>

            <div className="relative">
              <div className="absolute inset-0 flex items-center">
                <span className="w-full border-t border-gray-200"></span>
              </div>
              <div className="relative flex justify-center text-xs uppercase">
                <span className="bg-gray-50 px-3 text-gray-400 font-bold">Or describe the item</span>
              </div>
            </div>

            {/* Text Input Area */}
            <form onSubmit={handleTextSubmit} className="space-y-3">
              <div className="relative">
                <textarea
                  value={inputText}
                  onChange={(e) => setInputText(e.target.value)}
                  placeholder="e.g., 'Kryptonite U-lock', 'Bicycle tune-up service', 'Lazer helmet from Amazon'..."
                  className="w-full h-32 p-4 rounded-xl border border-gray-200 shadow-sm focus:ring-2 focus:ring-red-500 focus:border-red-500 outline-none transition-all resize-none"
                />
              </div>
              <button
                type="submit"
                disabled={!inputText.trim()}
                style={{ backgroundColor: HARVARD_CRIMSON }}
                className="w-full text-white font-bold py-4 px-6 rounded-xl shadow-lg hover:opacity-90 disabled:opacity-50 disabled:cursor-not-allowed transition-all flex items-center justify-center"
              >
                Analyze Description
              </button>
            </form>

            {state.error && (
              <div className="p-4 bg-red-50 border border-red-200 rounded-lg text-red-700 text-sm flex items-center">
                <i className="fas fa-exclamation-circle mr-2"></i>
                {state.error}
              </div>
            )}
          </div>
        )}

        {state.isAnalyzing && (
          <div className="flex flex-col items-center justify-center py-20 animate-pulse">
            <div className="relative w-20 h-20 mb-6">
              <div className="absolute inset-0 border-4 border-gray-200 rounded-full"></div>
              <div className="absolute inset-0 border-4 border-red-600 rounded-full border-t-transparent animate-spin"></div>
            </div>
            <h3 className="text-xl font-bold text-gray-800">Analyzing Eligibility...</h3>
            <p className="text-gray-500 mt-2">Checking Harvard Commuter Choice guidelines</p>
          </div>
        )}

        {state.result && (
          <ResultDisplay result={state.result} onReset={resetAnalysis} />
        )}
      </main>

      <footer className="py-8 bg-white border-t border-gray-200 mt-auto">
        <div className="max-w-5xl mx-auto px-4 text-center">
          <p className="text-sm text-gray-500">
            &copy; {new Date().getFullYear()} Harvard University. For official inquiries, contact <a href="mailto:commuterchoice@harvard.edu" className="text-red-700 font-medium hover:underline">commuterchoice@harvard.edu</a>.
          </p>
          <p className="text-[10px] text-gray-400 mt-2 uppercase tracking-widest">
            This tool uses AI for estimation. Official determinations are made by program staff.
          </p>
        </div>
      </footer>
    </div>
  );
};

export default App;

