import React from 'react';
import { AnalysisResult, EligibilityStatus } from '../types';
import { BIKE_LANE_GREEN, HARVARD_CRIMSON } from '../constants';

interface ResultDisplayProps {
  result: AnalysisResult;
  onReset: () => void;
}

const ResultDisplay: React.FC<ResultDisplayProps> = ({ result, onReset }) => {
  const getStatusConfig = (status: EligibilityStatus) => {
    switch (status) {
      case EligibilityStatus.ELIGIBLE:
        return {
          icon: 'fa-thumbs-up',
          color: 'text-emerald-600',
          bg: 'bg-emerald-50',
          border: 'border-emerald-200',
          label: 'GREEN LIGHT: ELIGIBLE'
        };
      case EligibilityStatus.INELIGIBLE:
        return {
          icon: 'fa-ban',
          color: 'text-red-600',
          bg: 'bg-red-50',
          border: 'border-red-200',
          label: 'STOP: INELIGIBLE'
        };
      case EligibilityStatus.ON_THE_FENCE:
      case EligibilityStatus.UNCLEAR:
      default:
        return {
          icon: 'fa-route',
          color: 'text-amber-600',
          bg: 'bg-amber-50',
          border: 'border-amber-200',
          label: 'CAUTION: REVIEW NEEDED'
        };
    }
  };

  const config = getStatusConfig(result.status);
  const showContactButton = result.status === EligibilityStatus.ON_THE_FENCE || result.status === EligibilityStatus.UNCLEAR;

  const mailtoLink = `mailto:commuterchoice@harvard.edu?subject=Eligibility Inquiry: ${result.itemName || 'Bike Item'}&body=Hi CommuterChoice Team,%0D%0A%0D%0AI would like to verify if the following item is eligible for the Bike Commuter Benefit:%0D%0A%0D%0AItem: ${result.itemName || 'Not specified'}%0D%0ACost: ${result.estimatedCost || 'Not specified'}%0D%0A%0D%0AThank you!`;

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className={`p-8 rounded-2xl border-4 ${config.bg} ${config.border} relative overflow-hidden`}>
        <div className="absolute top-[-20px] right-[-20px] opacity-10 rotate-12">
            <i className={`fas ${config.icon} text-9xl ${config.color}`}></i>
        </div>

        <div className="relative z-10 flex flex-col items-center text-center">
            <div className={`w-16 h-16 rounded-full flex items-center justify-center ${config.color} border-4 border-current mb-4 bg-white`}>
                <i className={`fas ${config.icon} text-2xl`}></i>
            </div>
            <h2 className={`text-2xl font-black tracking-tight ${config.color}`}>{config.label}</h2>
            {result.itemName && (
                <div className="mt-2 inline-block px-3 py-1 bg-white rounded-full border border-gray-200 text-sm font-bold text-gray-600">
                    {result.itemName}
                </div>
            )}
        </div>
      </div>

      <div className="bg-white rounded-2xl shadow-xl shadow-gray-200/50 border border-gray-100 overflow-hidden">
        <div className="bg-gray-50 px-6 py-3 border-b border-gray-100 flex items-center justify-between">
            <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Technician Analysis</span>
            <i className="fas fa-wrench text-gray-300 text-xs"></i>
        </div>
        <div className="p-6">
            <p className="text-gray-800 leading-relaxed font-medium">
            {result.reasoning}
            </p>

            <div className="mt-8">
                <h3 className="text-xs font-black text-gray-400 uppercase tracking-widest mb-4 flex items-center">
                    <span className="mr-2">Route Information</span>
                    <div className="flex-grow h-px bg-gray-100"></div>
                </h3>
                <ul className="space-y-3">
                {result.recommendations.map((rec, i) => (
                    <li key={i} className="flex items-start bg-gray-50 p-3 rounded-xl border border-gray-100">
                        <i className="fas fa-caret-right text-red-600 mt-1 mr-3"></i>
                        <span className="text-gray-700 text-sm font-medium">{rec}</span>
                    </li>
                ))}
                </ul>
            </div>
        </div>
      </div>

      <div className="flex flex-col gap-3">
        {showContactButton && (
          <a
            href={mailtoLink}
            className="w-full bg-amber-500 hover:bg-amber-600 text-white font-black py-4 px-6 rounded-xl text-center transition-all shadow-lg flex items-center justify-center uppercase tracking-wider"
          >
            <i className="fas fa-headset mr-2"></i> Open Support Ticket
          </a>
        )}
        <button
          onClick={onReset}
          className="w-full bg-gray-900 hover:bg-black text-white font-black py-4 px-6 rounded-xl transition-all shadow-lg flex items-center justify-center uppercase tracking-wider"
        >
          <i className="fas fa-bicycle mr-2"></i> Run Another Check
        </button>
      </div>

      <div className="bg-white p-4 rounded-xl border border-dashed border-gray-300 flex items-start">
        <div className="bg-red-100 text-red-700 p-2 rounded-lg mr-3">
            <i className="fas fa-receipt"></i>
        </div>
        <div className="space-y-2">
            <p className="text-[11px] text-gray-500 leading-tight">
                <strong>NAME CHECK:</strong> Receipts must be in the <strong>eligible employee's name</strong>. Expenses in a spouse's name will be rejected.
            </p>
            <p className="text-[11px] text-gray-500 leading-tight">
                <strong>PRO TIP:</strong> Always keep your itemized receipt. For <strong>Bluebikes</strong>, you can find your receipts in the Bluebikes app or website.
            </p>
        </div>
      </div>
    </div>
  );
};

