             <div className="h-2 w-24 bg-red-600"></div>
             <p className="text-black max-w-lg font-bold text-lg leading-snug">
               Quickly scan receipts or describe bike gear to see if you can get reimbursed.
             </p>
          </div>
        </div>

        {!state.result && !state.isAnalyzing && (
          <div className="grid md:grid-cols-2 gap-8 animate-in fade-in slide-in-from-left-4 duration-700">
            {/* Image Upload Area */}
            <div 
              onClick={() => fileInputRef.current?.click()}
              className="bg-white border-4 border-black p-8 flex flex-col items-start justify-end h-96 brutalist-shadow cursor-pointer hover:-translate-x-1 hover:-translate-y-1 hover:shadow-[12px_12px_0px_0px_rgba(0,0,0,1)] transition-all group relative overflow-hidden"
            >
              <div className="absolute top-6 left-6 text-4xl text-black group-hover:scale-110 transition-transform">
                <i className="fas fa-camera-retro"></i>
              </div>
              <div className="absolute top-6 right-6 opacity-10 text-8xl">
                 <i className="fas fa-receipt"></i>
              </div>

              <div className="w-full">
                <h3 className="text-3xl font-black text-black uppercase leading-none mb-2">Upload<br/>Receipt</h3>
                <p className="text-sm text-gray-500 font-bold uppercase tracking-wider italic">JPG, PNG or PDF</p>
              </div>
              <input 
                type="file" 
                ref={fileInputRef} 
                onChange={handleFileUpload} 
                className="hidden" 
                accept="image/*"
              />
            </div>

            {/* Text Input Area */}
            <div className="bg-white border-4 border-black p-8 flex flex-col h-96 brutalist-shadow hover:-translate-x-1 hover:-translate-y-1 hover:shadow-[12px_12px_0px_0px_rgba(0,0,0,1)] transition-all">
              <form onSubmit={handleTextSubmit} className="flex flex-col h-full gap-4">
                <div className="flex-grow">
                  <label className="text-[10px] font-black uppercase tracking-[0.3em] text-gray-400 block mb-2">Item Description</label>
                  <textarea
                    value={inputText}
                    onChange={(e) => setInputText(e.target.value)}
                    placeholder="Describe your purchase... (e.g. 'Safety vest', 'New lock')"
                    className="w-full h-44 bg-gray-50 p-4 border-2 border-transparent focus:border-black outline-none transition-all resize-none font-bold text-lg placeholder:text-gray-300"
                  />
                </div>
                <button
                  type="submit"
                  disabled={!inputText.trim()}
                  className="w-full bg-black text-white font-black py-5 px-6 brutalist-button hover:bg-red-700 disabled:bg-gray-200 disabled:text-gray-400 transition-all uppercase tracking-widest text-sm"
                >
                  Analyze Item →
                </button>
              </form>
            </div>
          </div>
        )}

        {state.isAnalyzing && (
          <div className="flex flex-col items-start py-20 animate-pulse">
            <div className="text-9xl font-black text-black leading-none uppercase italic opacity-10 select-none pointer-events-none mb-4">
              Processing
            </div>
