import { GoogleGenAI, Type } from "@google/genai";
import { SYSTEM_PROMPT } from "../constants";
import { AnalysisResult } from "../types";

export const analyzeBikePurchase = async (
  input: string | { data: string; mimeType: string }
): Promise<AnalysisResult> => {
  const apiKey = process.env.API_KEY;

  if (!apiKey) {
    throw new Error("API Key is missing. Please configure the environment variable API_KEY.");
  }

  const ai = new GoogleGenAI({ apiKey });

  const contents: any[] = [];

  if (typeof input === 'string') {
    contents.push({ text: `User Input: ${input}\n\nTask: Analyze this description for bike benefit eligibility.` });
  } else {
    contents.push({
      inlineData: input
    });
    contents.push({ text: "Task: Analyze this image. If it is a receipt, extract the items and name. If it is a product, determine its eligibility. Return JSON." });
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: { parts: contents },
      config: {
        systemInstruction: SYSTEM_PROMPT,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            status: { type: Type.STRING },
            itemName: { type: Type.STRING },
            reasoning: { type: Type.STRING },
            recommendations: {
              type: Type.ARRAY,
              items: { type: Type.STRING }
            },
            isReceiptDetected: { type: Type.BOOLEAN },
            estimatedCost: { type: Type.STRING }
          },
          required: ["status", "reasoning", "recommendations", "isReceiptDetected"]
        }
      },
    });

    const text = response.text;
    if (!text) throw new Error("The AI provided an empty response.");

    return JSON.parse(text) as AnalysisResult;
  } catch (error: any) {
    console.error("Gemini Analysis Error:", error);

    // Provide user-friendly error messages
    if (error.message?.includes("API_KEY_INVALID")) {
      throw new Error("The provided API key is invalid. Please check your configuration.");
    }

    throw new Error(error.message || "Failed to analyze the item. Please try again.");
  }
};

import React, { useState, useRef } from 'react';
import Header from './components/Header';
import ResultDisplay from './components/ResultDisplay';
import { analyzeBikePurchase } from './services/geminiService';
import { AnalysisState } from './types';

const App: React.FC = () => {
  const [state, setState] = useState<AnalysisState>({
    isAnalyzing: false,
    result: null,
    error: null,
  });
  const [inputText, setInputText] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setState({ ...state, isAnalyzing: true, error: null });

    try {
      const reader = new FileReader();
      reader.onload = async (e) => {
        const base64Data = e.target?.result?.toString().split(',')[1];
        if (base64Data) {
          try {
            const result = await analyzeBikePurchase({
              data: base64Data,
              mimeType: file.type,
            });
            setState({ isAnalyzing: false, result, error: null });
          } catch (err: any) {
            setState({ isAnalyzing: false, result: null, error: err.message || 'Analysis failed.' });
          }
        }
      };
      reader.readAsDataURL(file);
    } catch (err) {
      setState({ isAnalyzing: false, result: null, error: 'Failed to process file.' });
    }
  };

  const handleTextSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputText.trim()) return;

    setState({ ...state, isAnalyzing: true, error: null });

    try {
      const result = await analyzeBikePurchase(inputText);
      setState({ isAnalyzing: false, result, error: null });
    } catch (err: any) {
      setState({ isAnalyzing: false, result: null, error: err.message || 'Failed to analyze text.' });
    }
  };

  const resetAnalysis = () => {
    setState({ isAnalyzing: false, result: null, error: null });
    setInputText('');
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  return (
    <div className="min-h-screen bg-[#f0f0f0] flex flex-col selection:bg-black selection:text-white">
      <Header />

      <main className="flex-grow max-w-4xl mx-auto w-full px-6 py-12">
        <div className="mb-16">
          <h2 className="text-6xl md:text-8xl font-black text-black mb-6 tracking-tighter leading-[0.9] uppercase italic">
            Eligibility Check
          </h2>
          <div className="flex flex-col md:flex-row md:items-center gap-4">
             <div className="h-2 w-24 bg-red-600"></div>
             <p className="text-black max-w-lg font-bold text-lg leading-snug">
               Quickly scan receipts or describe bike gear to see if you can get reimbursed.
             </p>
          </div>
        </div>

        {state.error && (
          <div className="mb-8 bg-red-600 text-white p-6 border-4 border-black brutalist-shadow-sm animate-in slide-in-from-top-4 duration-300">
            <div className="flex items-center gap-4">
              <i className="fas fa-circle-exclamation text-3xl"></i>
              <div>
                <h4 className="font-black uppercase tracking-tight">System Error</h4>
                <p className="text-sm font-bold opacity-90">{state.error}</p>
              </div>
              <button 
                onClick={() => setState({ ...state, error: null })}
                className="ml-auto bg-white text-black px-4 py-2 font-black text-xs uppercase"
              >
                Dismiss
              </button>
            </div>
          </div>
        )}

        {!state.result && !state.isAnalyzing && (
          <div className="grid md:grid-cols-2 gap-8 animate-in fade-in slide-in-from-left-4 duration-700">
            {/* Image Upload Area */}
            <div 
              onClick={() => fileInputRef.current?.click()}
              className="bg-white border-4 border-black p-8 flex flex-col items-start justify-end h-96 brutalist-shadow cursor-pointer hover:-translate-x-1 hover:-translate-y-1 hover:shadow-[12px_12px_0px_0px_rgba(0,0,0,1)] transition-all group relative overflow-hidden"
            >
              <div className="absolute top-6 left-6 text-4xl text-black group-hover:scale-110 transition-transform">
                <i className="fas fa-camera-retro"></i>
              </div>
              <div className="absolute top-6 right-6 opacity-10 text-8xl">
                 <i className="fas fa-receipt"></i>
              </div>

              <div className="w-full">
                <h3 className="text-3xl font-black text-black uppercase leading-none mb-2">Upload<br/>Receipt</h3>
                <p className="text-sm text-gray-500 font-bold uppercase tracking-wider italic">JPG, PNG or PDF</p>
              </div>
              <input 
                type="file" 
                ref={fileInputRef} 
                onChange={handleFileUpload} 
                className="hidden" 
                accept="image/*,application/pdf"
              />
            </div>

            {/* Text Input Area */}
            <div className="bg-white border-4 border-black p-8 flex flex-col h-96 brutalist-shadow hover:-translate-x-1 hover:-translate-y-1 hover:shadow-[12px_12px_0px_0px_rgba(0,0,0,1)] transition-all">
              <form onSubmit={handleTextSubmit} className="flex flex-col h-full gap-4">
                <div className="flex-grow">
                  <label className="text-[10px] font-black uppercase tracking-[0.3em] text-gray-400 block mb-2">Item Description</label>
                  <textarea
                    value={inputText}
                    onChange={(e) => setInputText(e.target.value)}
                    placeholder="Describe your purchase... (e.g. 'Safety vest', 'New lock')"
                    className="w-full h-44 bg-gray-50 p-4 border-2 border-transparent focus:border-black outline-none transition-all resize-none font-bold text-lg placeholder:text-gray-300"
                  />
                </div>
                <button
                  type="submit"
                  disabled={!inputText.trim()}
                  className="w-full bg-black text-white font-black py-5 px-6 brutalist-button hover:bg-red-700 disabled:bg-gray-200 disabled:text-gray-400 transition-all uppercase tracking-widest text-sm"
                >
                  Analyze Item →
                </button>
              </form>
            </div>
          </div>
        )}

        {state.isAnalyzing && (
          <div className="flex flex-col items-start py-20 animate-pulse">
            <div className="text-9xl font-black text-black leading-none uppercase italic opacity-10 select-none pointer-events-none mb-4">
              Processing
            </div>
            <div className="w-full h-8 bg-black relative overflow-hidden mb-8">
                <div className="absolute inset-y-0 left-0 bg-red-600 animate-[loading-bar_1.5s_infinite_ease-in-out]" style={{ width: '40%' }}></div>
            </div>
            <h3 className="text-4xl font-black text-black tracking-tighter uppercase">Reviewing Guidelines...</h3>

            <style>{`
                @keyframes loading-bar {
                    0% { transform: translateX(-100%); }
                    100% { transform: translateX(300%); }
                }
            `}</style>
          </div>
        )}

        {state.result && (
          <ResultDisplay result={state.result} onReset={resetAnalysis} />
        )}
      </main>

      <footer className="py-12 bg-black text-white mt-auto">
        <div className="max-w-4xl mx-auto px-6 flex flex-col md:flex-row justify-between items-start md:items-end gap-8">
          <div>
            <div className="flex items-center gap-2 mb-4">
               <div className="w-8 h-8 bg-white text-black flex items-center justify-center font-black">H</div>
               <div className="text-lg font-black tracking-tighter uppercase italic">CommuterChoice</div>
            </div>
            <p className="text-[10px] text-gray-500 font-bold uppercase tracking-widest">
              &copy; {new Date().getFullYear()} Harvard University
            </p>
          </div>
          <div className="text-left md:text-right">
            <p className="text-xs text-gray-400 font-bold uppercase mb-2">Need Support?</p>
            <a href="mailto:commuterchoice@harvard.edu" className="text-2xl font-black hover:text-red-500 transition-colors underline decoration-4 underline-offset-4">
              Contact CommuterChoice
            </a>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

