import React, { useState, useRef } from 'react';
import ReactDOM from 'react-dom/client';
import { GoogleGenAI, Type } from "@google/genai";

// --- CONSTANTS & TYPES ---
const HARVARD_CRIMSON = '#A51C30';

enum EligibilityStatus {
  ELIGIBLE = 'ELIGIBLE',
  INELIGIBLE = 'INELIGIBLE',
  ON_THE_FENCE = 'ON_THE_FENCE',
  UNCLEAR = 'UNCLEAR'
}

interface AnalysisResult {
  status: EligibilityStatus;
  reasoning: string;
  recommendations: string[];
  itemName?: string;
  estimatedCost?: string;
  isReceiptDetected: boolean;
}

const SYSTEM_PROMPT = `
You are the "Is This Eligible?" assistant for Harvard University's Bike Commuter Benefit program. 
Analyze purchases based on these rules:
- ELIGIBLE: Bicycles (new/used), repairs, storage, helmets, lights, locks, bells, racks, fenders, panniers, bike computers, safety apparel (reflective), Bluebikes memberships/fees, Nemo/CargoB services.
- INELIGIBLE: Flashlights (not bike specific), general clothing (standard sunglasses/jackets), food, races, gym memberships, non-Bluebikes share systems (e.g. Citi Bike).
- MANDATORY: Must be in the employee's name.
- UNCLEAR: If unsure or "on the fence", tell user to contact commuterchoice@harvard.edu.
Return JSON: {status, itemName, reasoning, recommendations[], isReceiptDetected, estimatedCost}
`;

// --- SERVICE ---
const analyzeBikePurchase = async (
  input: string | { data: string; mimeType: string }
): Promise<AnalysisResult> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) throw new Error("API Key missing in environment.");

  const ai = new GoogleGenAI({ apiKey });
  const contents: any[] = [];

  if (typeof input === 'string') {
    contents.push({ text: `Analyze: ${input}` });
  } else {
    contents.push({ inlineData: input }, { text: "Analyze this image (receipt or product) for Harvard bike benefit eligibility. Return JSON." });
  }

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { parts: contents },
    config: {
      systemInstruction: SYSTEM_PROMPT,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          status: { type: Type.STRING },
          itemName: { type: Type.STRING },
          reasoning: { type: Type.STRING },
          recommendations: { type: Type.ARRAY, items: { type: Type.STRING } },
          isReceiptDetected: { type: Type.BOOLEAN },
          estimatedCost: { type: Type.STRING }
        },
        required: ["status", "reasoning", "recommendations", "isReceiptDetected"]
      }
    },
  });

  return JSON.parse(response.text) as AnalysisResult;
};

