export enum EligibilityStatus {
  ELIGIBLE = 'ELIGIBLE',
  INELIGIBLE = 'INELIGIBLE',
  ON_THE_FENCE = 'ON_THE_FENCE',
  UNCLEAR = 'UNCLEAR'
}

export interface GroundingSource {
  uri: string;
  title: string;
}

export interface AnalysisResult {
  status: EligibilityStatus;
  reasoning: string;
  recommendations: string[];
  itemName?: string;
  estimatedCost?: string;
  isReceiptDetected: boolean;
  followUpQuestions?: string[];
  groundingUrls?: GroundingSource[];
}

export interface AnalysisState {
  isAnalyzing: boolean;
  result: AnalysisResult | null;
  error: string | null;
}

import { GoogleGenAI, Type } from "@google/genai";
import { SYSTEM_PROMPT } from "../constants";
import { AnalysisResult, GroundingSource } from "../types";

export const analyzeBikePurchase = async (
  input: string | { data: string; mimeType: string }
): Promise<AnalysisResult> => {
  const apiKey = process.env.API_KEY;

  if (!apiKey) {
    throw new Error("API Key is missing. Please configure the environment variable API_KEY.");
  }

  const ai = new GoogleGenAI({ apiKey: apiKey as string });

  const contents: any[] = [];
  const isImage = typeof input !== 'string';

  if (typeof input === 'string') {
    contents.push({ text: `User Input: ${input}\n\nTask: Analyze this description or product link for bike benefit eligibility.` });
  } else {
    contents.push({
      inlineData: input
    });
    contents.push({ text: "Task: Analyze this image/PDF. Extract items and name. Determine eligibility. If ambiguous, ask follow-up questions." });
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: { parts: contents },
      config: {
        systemInstruction: SYSTEM_PROMPT,
        // Only use googleSearch for text inputs that might contain links or need external verification
        tools: !isImage ? [{ googleSearch: {} }] : undefined,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            status: { type: Type.STRING },
            itemName: { type: Type.STRING },
            reasoning: { type: Type.STRING },
            recommendations: {
              type: Type.ARRAY,
              items: { type: Type.STRING }
            },
            isReceiptDetected: { type: Type.BOOLEAN },
            estimatedCost: { type: Type.STRING },
            followUpQuestions: {
              type: Type.ARRAY,
              items: { type: Type.STRING }
            }
          },
          required: ["status", "reasoning", "recommendations", "isReceiptDetected"]
        }
      },
    });

    const text = response.text;
    if (!text) {
      throw new Error("The AI provided an empty response.");
    }

    const result = JSON.parse(text) as AnalysisResult;

    // Extract grounding chunks if available
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    if (groundingChunks && Array.isArray(groundingChunks)) {
      const sources: GroundingSource[] = [];
      groundingChunks.forEach((chunk: any) => {
        if (chunk.web && chunk.web.uri) {
          sources.push({
            uri: chunk.web.uri,
            title: chunk.web.title || chunk.web.uri
          });
        }
      });
      if (sources.length > 0) {
        result.groundingUrls = sources;
      }
    }

    return result;
  } catch (error: any) {
    console.error("Gemini Analysis Error:", error);
    throw new Error(error.message || "Failed to analyze the item.");
  }
};

import React, { useState, useRef } from 'react';
import Header from './components/Header';
import ResultDisplay from './components/ResultDisplay';
import { analyzeBikePurchase } from './services/geminiService';
import { AnalysisState } from './types';

const App: React.FC = () => {
  const [state, setState] = useState<AnalysisState>({
    isAnalyzing: false,
    result: null,
    error: null,
  });
  const [inputText, setInputText] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setState({ ...state, isAnalyzing: true, error: null });

    try {
      const reader = new FileReader();
      reader.onload = async (e) => {
        const base64Data = e.target?.result?.toString().split(',')[1];
        if (base64Data) {
          try {
            const result = await analyzeBikePurchase({
              data: base64Data,
              mimeType: file.type,
            });
            setState({ isAnalyzing: false, result, error: null });
          } catch (err: any) {
            setState({ isAnalyzing: false, result: null, error: err.message || 'Analysis failed.' });
          }
        }
      };
      reader.readAsDataURL(file);
    } catch (err) {
      setState({ isAnalyzing: false, result: null, error: 'Failed to process file.' });
    }
  };

  const handleTextSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputText.trim()) return;

    setState({ ...state, isAnalyzing: true, error: null });

    try {
      const result = await analyzeBikePurchase(inputText);
      setState({ isAnalyzing: false, result, error: null });
    } catch (err: any) {
      setState({ isAnalyzing: false, result: null, error: err.message || 'Failed to analyze text.' });
    }
  };

  const resetAnalysis = () => {
    setState({ isAnalyzing: false, result: null, error: null });
    setInputText('');
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  return (
    <div className="min-h-screen bg-[#f0f0f0] flex flex-col selection:bg-black selection:text-white">
      <Header />

