              <div>
                <h4 className="font-black uppercase tracking-tight">System Error</h4>
                <p className="text-sm font-bold opacity-90">{state.error}</p>
              </div>
              <button 
                onClick={() => setState({ ...state, error: null })}
                className="ml-auto bg-white text-black px-4 py-2 font-black text-xs uppercase"
              >
                Dismiss
              </button>
            </div>
          </div>
        )}

        {!state.result && !state.isAnalyzing && (
          <div className="grid md:grid-cols-2 gap-8 animate-in fade-in slide-in-from-left-4 duration-700">
            {/* Image Upload Area */}
            <div 
              onClick={() => fileInputRef.current?.click()}
