import { GoogleGenAI, Type } from "@google/genai";
import { SYSTEM_PROMPT } from "../constants";
import { AnalysisResult, EligibilityStatus, GroundingSource } from "../types";

// Simple session-based cache to avoid duplicate API calls for the same text
const textCache = new Map<string, AnalysisResult>();

// Local heuristics for instant rejection to save API quota
const checkLocalHeuristics = (input: string): AnalysisResult | null => {
  const text = input.toLowerCase();

  // High-confidence rejection keywords based on policy
  const forbidden = [
    { keywords: ['mbta', 'charlie card', 'charlie store', 'commuter rail'], reason: "MBTA and Transit passes are handled via the separate Transit Benefit program, not the Bike Benefit." },
    { keywords: ['garage door', 'rolling steel door', 'door spring', 'dock leveler'], reason: "This appears to be institutional facility maintenance. The bike benefit is for personal commuting gear only." },
    { keywords: ['parking fee', 'car parking', 'garage fee'], reason: "Car parking fees are strictly ineligible for reimbursement under the bike commuter program." },
    { keywords: ['traffic cone', 'barricade', 'road sign'], reason: "Traffic control equipment is for facility management and is not eligible for personal reimbursement." }
  ];

  for (const rule of forbidden) {
    if (rule.keywords.some(k => text.includes(k))) {
      return {
        status: EligibilityStatus.INELIGIBLE,
        itemName: "Detected Policy Violation",
        reasoning: rule.reason,
        recommendations: ["Check the Harvard Transit Benefit for MBTA needs", "Contact Facilities for building maintenance"],
        isReceiptDetected: false,
        estimatedCost: "N/A"
      };
    }
  }

  return null;
};

export const analyzeBikePurchase = async (
  input: string | { data: string; mimeType: string }
): Promise<AnalysisResult> => {
  const apiKey = process.env.API_KEY;

  if (!apiKey) {
    throw new Error("API Key is missing. Please configure the environment variable API_KEY.");
  }

  // 1. Check local heuristics and cache for text inputs
  if (typeof input === 'string') {
    const trimmedInput = input.trim();
    if (textCache.has(trimmedInput)) {
      return textCache.get(trimmedInput)!;
    }

    const heuristicResult = checkLocalHeuristics(trimmedInput);
    if (heuristicResult) return heuristicResult;
  }

  const ai = new GoogleGenAI({ apiKey: apiKey as string });

  const contents: any[] = [];
  const isImage = typeof input !== 'string';

  if (typeof input === 'string') {
    contents.push({ text: `User Input: ${input}\n\nTask: Analyze this description or product link for bike benefit eligibility.` });
  } else {
    contents.push({
      inlineData: input
    });
    contents.push({ text: "Task: Analyze this image/PDF. Extract items and name. Determine eligibility. If ambiguous, ask follow-up questions." });
  }

  try {
    const response = await ai.models.generateContent({
      // Switching to Lite for better quota/efficiency
      model: 'gemini-flash-lite-latest',
      contents: { parts: contents },
      config: {
        systemInstruction: SYSTEM_PROMPT,
        tools: !isImage ? [{ googleSearch: {} }] : undefined,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            status: { type: Type.STRING },
            itemName: { type: Type.STRING },
            reasoning: { type: Type.STRING },
            recommendations: {
              type: Type.ARRAY,
              items: { type: Type.STRING }
            },
            isReceiptDetected: { type: Type.BOOLEAN },
            estimatedCost: { type: Type.STRING },
            followUpQuestions: {
              type: Type.ARRAY,
              items: { type: Type.STRING }
            }
          },
          required: ["status", "reasoning", "recommendations", "isReceiptDetected"]
        }
      },
    });

    const text = response.text;
    if (!text) {
      throw new Error("The AI provided an empty response.");
    }

    const result = JSON.parse(text) as AnalysisResult;

    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    if (groundingChunks && Array.isArray(groundingChunks)) {
      const sources: GroundingSource[] = [];
      groundingChunks.forEach((chunk: any) => {
        if (chunk.web && chunk.web.uri) {
          sources.push({
            uri: chunk.web.uri,
            title: chunk.web.title || chunk.web.uri
          });
        }
      });
      if (sources.length > 0) {
        result.groundingUrls = sources;
      }
    }

    // Cache the successful result if it's text
    if (typeof input === 'string') {
      textCache.set(input.trim(), result);
    }

    return result;
  } catch (error: any) {
    if (error.message?.includes('429')) {
      throw new Error("The system is currently busy (Rate Limit). Please wait a few seconds and try again.");
    }
    console.error("Gemini Analysis Error:", error);
    throw new Error(error.message || "Failed to analyze the item.");
  }
};

import React, { useState, useRef, useMemo } from 'react';
import Header from './components/Header';
import ResultDisplay from './components/ResultDisplay';
import { analyzeBikePurchase } from './services/geminiService';
import { AnalysisState } from './types';
import { EXAMPLE_PURCHASES } from './constants';

const App: React.FC = () => {
  const [state, setState] = useState<AnalysisState>({
    isAnalyzing: false,
    result: null,
    error: null,
  });
  const [inputText, setInputText] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const randomExample = useMemo(() => {
    return EXAMPLE_PURCHASES[Math.floor(Math.random() * EXAMPLE_PURCHASES.length)];
  }, []);

  // Helper to resize image before sending to API
  const resizeImage = (file: File): Promise<{ data: string, mimeType: string }> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = (event) => {
        const img = new Image();
        img.src = event.target?.result as string;
        img.onload = () => {
          const canvas = document.createElement('canvas');
          const MAX_WIDTH = 1024;
          const MAX_HEIGHT = 1024;
          let width = img.width;
          let height = img.height;

          if (width > height) {
            if (width > MAX_WIDTH) {
              height *= MAX_WIDTH / width;
              width = MAX_WIDTH;
            }
          } else {
            if (height > MAX_HEIGHT) {
              width *= MAX_HEIGHT / height;
              height = MAX_HEIGHT;
            }
          }

          canvas.width = width;
          canvas.height = height;
          const ctx = canvas.getContext('2d');
          ctx?.drawImage(img, 0, 0, width, height);

          const dataUrl = canvas.toDataURL('image/jpeg', 0.8);
          const base64 = dataUrl.split(',')[1];
          resolve({ data: base64, mimeType: 'image/jpeg' });
        };
        img.onerror = reject;
      };
      reader.onerror = reject;
    });
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setState({ ...state, isAnalyzing: true, error: null });

    try {
      let payload;
      if (file.type.startsWith('image/')) {
        // Optimize images to save tokens and quota
        payload = await resizeImage(file);
      } else {
        // PDFs or other files sent as-is (limited compression possible)
        const base64Data = await new Promise<string>((resolve) => {
          const reader = new FileReader();
          reader.onload = (e) => resolve(e.target?.result?.toString().split(',')[1] || "");
          reader.readAsDataURL(file);
        });
        payload = { data: base64Data, mimeType: file.type };
      }

      const result = await analyzeBikePurchase(payload);
      setState({ isAnalyzing: false, result, error: null });
    } catch (err: any) {
      setState({ isAnalyzing: false, result: null, error: err.message || 'Analysis failed.' });
    }
  };

  const handleTextSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputText.trim()) return;

    setState({ ...state, isAnalyzing: true, error: null });

    try {
      const result = await analyzeBikePurchase(inputText);
      setState({ isAnalyzing: false, result, error: null });
    } catch (err: any) {
      setState({ isAnalyzing: false, result: null, error: err.message || 'Failed to analyze text.' });
    }
  };

  const resetAnalysis = () => {
    setState({ isAnalyzing: false, result: null, error: null });
    setInputText('');
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  return (
    <div className="min-h-screen bg-[#f0f0f0] flex flex-col selection:bg-black selection:text-white">
      <Header />

      <main className="flex-grow max-w-4xl mx-auto w-full px-6 py-12">
        <div className="mb-16">
          <h2 className="text-6xl md:text-8xl font-black text-black mb-6 tracking-tighter leading-[0.9] uppercase italic">
            Eligibility Check
          </h2>
          <div className="flex flex-col md:flex-row md:items-center gap-4">
             <div className="h-2 w-24 bg-red-600"></div>
             <p className="text-black max-w-lg font-bold text-lg leading-snug">
               Quickly scan receipts, insert product links, or describe bike gear to see if you can get reimbursed.
             </p>
          </div>
        </div>

        {state.error && (
          <div className="mb-8 bg-red-600 text-white p-6 border-4 border-black brutalist-shadow-sm animate-in slide-in-from-top-4 duration-300">
            <div className="flex items-center gap-4">
              <i className="fas fa-circle-exclamation text-3xl"></i>
              <div>
                <h4 className="font-black uppercase tracking-tight">System Status</h4>
                <p className="text-sm font-bold opacity-90">{state.error}</p>
              </div>
              <button 
                onClick={() => setState({ ...state, error: null })}
                className="ml-auto bg-white text-black px-4 py-2 font-black text-xs uppercase"
              >
                Dismiss
              </button>
            </div>
          </div>
        )}

        {!state.result && !state.isAnalyzing && (
          <div className="grid md:grid-cols-2 gap-8 animate-in fade-in slide-in-from-left-4 duration-700">
            {/* Image Upload Area */}
            <div 
              onClick={() => fileInputRef.current?.click()}
              className="bg-white border-4 border-black p-8 flex flex-col items-start justify-end h-96 brutalist-shadow cursor-pointer hover:-translate-x-1 hover:-translate-y-1 hover:shadow-[12px_12px_0px_0px_rgba(0,0,0,1)] transition-all group relative overflow-hidden"
            >
              <div className="absolute top-6 left-6 text-4xl text-black group-hover:scale-110 transition-transform">
                <i className="fas fa-camera-retro"></i>
              </div>
              <div className="absolute top-6 right-6 opacity-10 text-8xl">
