            <div className="flex items-center gap-4">
              <div className={`w-3 h-3 rounded-full ${entry.status === EligibilityStatus.ELIGIBLE ? 'bg-emerald-500' : entry.status === EligibilityStatus.INELIGIBLE ? 'bg-red-600' : 'bg-amber-400'}`}></div>
              <div>
