             <div className="h-2 w-24 bg-red-600"></div>
             <p className="text-black max-w-lg font-bold text-lg leading-snug">
               Quickly scan receipts, insert product links, or describe bike gear to see if it’s eligible for the bike benefit program.
             </p>
          </div>
