import { GoogleGenAI, Type } from "@google/genai";
import { SYSTEM_PROMPT, AUTO_ELIGIBLE_KEYWORDS } from "../constants";
import { AnalysisResult, EligibilityStatus, GroundingSource } from "../types";

const textCache = new Map<string, AnalysisResult>();

const normalizeKey = (str: string) => str.toLowerCase().trim().replace(/[^a-z0-9]/g, '');

const checkHeuristics = (input: string): AnalysisResult | null => {
  const normalized = normalizeKey(input);
  const isPrivateParty = normalized.includes('craigslist') || normalized.includes('facebookmarketplace') || normalized.includes('privateparty') || normalized.includes('marketplace') || normalized.includes('fromafriend');
  const isBike = normalized.includes('bike') || normalized.includes('bicycle') || normalized.includes('frame');

  // 1. Private Party Rule Heuristic
  if (isPrivateParty && !isBike) {
    return {
      status: EligibilityStatus.INELIGIBLE,
      itemName: "Private Party Purchase",
      reasoning: "A bike is the only item that may be purchased from a private party. Any other bike-related purchases (gear, locks, etc.) made from an individual or private party are not eligible for reimbursement.",
      recommendations: ["Purchase accessories and gear from a commercial retailer to ensure eligibility."],
      isReceiptDetected: false,
      estimatedCost: "N/A"
    };
  }

  // 2. Negative Heuristics
  const forbidden = [
    {
      keys: ['flashlight', 'headlamp'],
      reason: "General-purpose flashlights and headlamps are not eligible because they are not bicycle-specific. The benefit only covers rechargeable bike lights or lights specifically designed for helmet mounting."
    },
    {
      keys: ['motorcycle', 'motorbike', 'moto'],
      reason: "Motorcycle gear (such as motorcycle helmets or jackets) is not eligible. The benefit specifically covers equipment for bicycle commuting."
    },
    { 
      keys: ['citibike', 'citi'], 
      reason: "Citi Bike is not eligible for reimbursement. The Harvard Bike Benefit only covers local Boston-area bike share services like Bluebikes and CargoB." 
    },
    { 
      keys: ['mbta', 'charlie', 'rail'], 
      reason: "Public transit passes are not part of the Bike Benefit." 
    },
    { 
      keys: ['garage', 'rolling', 'door', 'spring'], 
      reason: "Facility maintenance is not eligible for personal gear reimbursement." 
    },
    { 
      keys: ['parking', 'fuel'], 
      reason: "Vehicle-related expenses are ineligible." 
    },
    {
      keys: ['carrack', 'roofrack', 'trunkrack', 'hitchrack', 'vehiclerack'],
      reason: "Car-mounted bike racks are considered vehicle accessories rather than cycling equipment and are not eligible for reimbursement under the bike benefit."
    },
    { 
      keys: ['socks', 'downjacket', 'downcoat', 'polo', 'tshirt'], 
      reason: "General-purpose apparel (like socks or down jackets) is ineligible. The benefit only covers clothing specifically designed for cycling, such as reflective safety gear or padded shorts." 
    }
  ];

  for (const rule of forbidden) {
    if (rule.keys.some(k => normalized.includes(k))) {
      return {
        status: EligibilityStatus.INELIGIBLE,
        itemName: "Non-Eligible Item",
        reasoning: rule.reason,
        recommendations: ["Bike benefit program details: https://transportation.harvard.edu/sustainable-transportation/bike-walk/bike-commuter-benefit"],
        isReceiptDetected: false,
        estimatedCost: "N/A"
      };
    }
  }

  // 3. Positive Heuristics
  for (const keyword of AUTO_ELIGIBLE_KEYWORDS) {
    if (normalized.includes(normalizeKey(keyword))) {
      const isBikeKeyword = keyword.includes('bike') || keyword.includes('frame');
      if (isPrivateParty && !isBikeKeyword) continue;

      let reasoning = `"${keyword}" is a standard piece of cycling equipment explicitly covered under the Harvard Bike Commuter Benefit program.`;

      if (normalized.includes('usedbike') || normalized.includes('usedframe') || normalized.includes('preownedbike')) {
        reasoning = "Used bicycles and used bike frames are eligible for reimbursement under the Harvard Bike Benefit program, even from private sellers.";
      } else if (normalized.includes('bikelight') || normalized.includes('helmetlight')) {
        reasoning = "Cycling-specific lighting, such as rechargeable bike lights or helmet-mounted lights, is eligible for reimbursement (when purchased from a retailer).";
      } else if (normalized.includes('cargob')) {
        reasoning = "CargoB is a local Boston-area cargo bike share service explicitly covered under the Harvard Bike Commuter Benefit program.";
      } else if (normalized.includes('nemo') || normalized.includes('roadsideassistance')) {
        reasoning = "Nemo services, including memberships and individual roadside assistance support, are covered under the Harvard Bike Commuter Benefit program.";
      } else if (normalized.includes('bluebikes')) {
        reasoning = "Bluebikes (the local Boston-area bike share) memberships are a core component of the Harvard Bike Commuter Benefit.";
      }

      return {
        status: EligibilityStatus.ELIGIBLE,
        itemName: keyword.charAt(0).toUpperCase() + keyword.slice(1),
        reasoning,
        recommendations: ["Save your itemized receipt", "Log into the Jawnt portal to submit your claim"],
        isReceiptDetected: false,
        estimatedCost: "N/A"
      };
    }
  }
  return null;
};

// Helper for exponential backoff retries
const withRetry = async <T>(fn: () => Promise<T>, retries = 3, delay = 2000): Promise<T> => {
  try {
    return await fn();
  } catch (error: any) {
    const isRateLimit = error.message?.includes('429') || error.status === 429 || error.message?.includes('RESOURCE_EXHAUSTED');
    if (retries > 0 && isRateLimit) {
      console.warn(`Rate limit hit. Retrying in ${delay}ms... (${retries} attempts left)`);
      await new Promise(resolve => setTimeout(resolve, delay));
      return withRetry(fn, retries - 1, delay * 2);
    }
    throw error;
  }
};

export const analyzeBikePurchase = async (
  input: string | { data: string; mimeType: string }
): Promise<AnalysisResult> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) throw new Error("API Key missing.");

  if (typeof input === 'string') {
    const key = normalizeKey(input);
    if (textCache.has(key)) return textCache.get(key)!;
    const hResult = checkHeuristics(input);
    if (hResult) {
      textCache.set(key, hResult);
      return hResult;
    }
  }

  const performAnalysis = async () => {
    const ai = new GoogleGenAI({ apiKey });
    const isImage = typeof input !== 'string';
    const urlRegex = /(https?:\/\/[^\s]+|www\.[^\s]+|[a-z0-9]+\.[a-z]{2,})/i;
    const needsSearch = !isImage && urlRegex.test(input);

    const contents = isImage ? 
      [{ inlineData: input }, { text: "Analyze this image for bike benefit eligibility. REMEMBER: Only bikes/frames are eligible from private parties. All other gear must be from a retailer. Check for bike-specificity." }] : 
      [{ text: `Evaluate this purchase for Harvard Bike Benefit: ${input}. REMEMBER: Only a bike/frame can be purchased from a private party. All other gear must be from a store.` }];

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: { parts: contents },
      config: {
        systemInstruction: SYSTEM_PROMPT,
        tools: needsSearch ? [{ googleSearch: {} }] : undefined,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            status: { type: Type.STRING },
            itemName: { type: Type.STRING },
            reasoning: { type: Type.STRING },
            recommendations: { type: Type.ARRAY, items: { type: Type.STRING } },
            isReceiptDetected: { type: Type.BOOLEAN },
            estimatedCost: { type: Type.STRING },
            followUpQuestions: { type: Type.ARRAY, items: { type: Type.STRING } }
          },
          required: ["status", "reasoning", "recommendations", "isReceiptDetected"]
        }
      },
    });

    let rawText = response.text || "";
    rawText = rawText.replace(/```json\n?/, '').replace(/\n?```/, '').trim();
    const result = JSON.parse(rawText) as AnalysisResult;

    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    if (groundingChunks) {
      const sources: GroundingSource[] = [];
      groundingChunks.forEach((c: any) => { if (c.web?.uri) sources.push({ uri: c.web.uri, title: c.web.title || "Reference" }); });
      if (sources.length > 0) result.groundingUrls = sources;
    }
    return result;
  };

  try {
    const result = await withRetry(performAnalysis);
    if (typeof input === 'string') textCache.set(normalizeKey(input), result);
    return result;
  } catch (error: any) {
    if (error.message?.includes('429') || error.message?.includes('RESOURCE_EXHAUSTED')) {
      throw new Error("The AI service is currently at capacity. Please wait a moment and try again.");
    }
    throw new Error(error.message || "Analysis failed.");
  }
};

import React, { useState, useRef, useMemo, useEffect } from 'react';
import Header from './components/Header';
import ResultDisplay from './components/ResultDisplay';
import HistoryLog from './components/HistoryLog';
