  useEffect(() => {
    trackPageView('Home');

    // Load History
    const savedHistory = localStorage.getItem('bike_benefit_history');
    if (savedHistory) {
      try { setHistory(JSON.parse(savedHistory)); } catch (e) { console.error(e); }
    }

    // Load Claimed Total
    const savedTotal = localStorage.getItem('bike_benefit_claimed_total');
    if (savedTotal) {
      setClaimedTotal(parseFloat(savedTotal) || 0);
    }
  }, []);

  const saveToHistory = (result: any) => {
