    setHistory(updated);
    localStorage.setItem('bike_benefit_history', JSON.stringify(updated));
    trackSearch(itemName, result.status);
  };

  const handleAddToTracker = (amount: string) => {
    const value = parseFloat(amount.replace(/[^0-9.]/g, ''));
