        reader.onload = (e) => resolve({ data: e.target?.result?.toString().split(',')[1] || "", mimeType: file.type });
        reader.readAsDataURL(file);
      });
      const result = await analyzeBikePurchase(payload);
      setState({ isAnalyzing: false, result, error: null });
      saveToHistory(result);
    } catch (err: any) {
      setState({ isAnalyzing: false, error: err.message });
    }
