import { GoogleGenAI, Type } from "@google/genai";
import { SYSTEM_PROMPT, AUTO_ELIGIBLE_KEYWORDS } from "../constants";
import { AnalysisResult, EligibilityStatus, GroundingSource } from "../types";

const textCache = new Map<string, AnalysisResult>();

const normalizeKey = (str: string) => str.toLowerCase().trim().replace(/[^a-z0-9]/g, '');

const checkHeuristics = (input: string): AnalysisResult | null => {
  const normalized = normalizeKey(input);
  const isPrivateParty = normalized.includes('craigslist') || normalized.includes('facebookmarketplace') || normalized.includes('privateparty') || normalized.includes('marketplace') || normalized.includes('fromafriend') || normalized.includes('fromaperson');

  // Refined bike detection: Must be the vehicle itself.
  // We exclude common parts keywords to ensure a "bike part" isn't treated as a "bike".
  const isFullVehicle = (normalized.includes('bicycle') || normalized.includes('bike') || normalized.includes('frame')) && 
                        !normalized.includes('part') && 
                        !normalized.includes('accessory') && 
                        !normalized.includes('gear') && 
                        !normalized.includes('lock') && 
                        !normalized.includes('helmet') && 
                        !normalized.includes('light') &&
                        !normalized.includes('tire') &&
                        !normalized.includes('tube');

  // 1. Private Party Rule Heuristic
  if (isPrivateParty) {
    if (isFullVehicle) {
      return {
        status: EligibilityStatus.ELIGIBLE,
        itemName: "Used Bicycle/Frame",
        reasoning: "Used bicycles and bike frames are eligible for reimbursement even when purchased from private parties (like Craigslist or Marketplace).",
        recommendations: ["Ensure you have a record of the transaction or a receipt from the seller.", "Submit your claim via the Jawnt portal."],
        isReceiptDetected: false,
        estimatedCost: "N/A"
      };
    } else {
      return {
        status: EligibilityStatus.INELIGIBLE,
        itemName: "Private Party Gear/Parts",
        reasoning: "While used bikes and bicycle frames are eligible from private sellers, the guidelines specify that all other gear, apparel, parts, and accessories must be purchased from a commercial retailer to qualify for the benefit.",
        recommendations: ["Purchase gear from a commercial bike shop or retailer next time.", "Check full guidelines: https://transportation.harvard.edu/sustainable-transportation/bike-walk/bike-commuter-benefit"],
        isReceiptDetected: false,
        estimatedCost: "N/A"
      };
    }
  }

  // 2. Negative Heuristics (Commercial Retailer implied or not specified)
  const forbidden = [
    {
      keys: ['flashlight', 'headlamp'],
      reason: "General-purpose flashlights and headlamps are not eligible. The benefit only covers rechargeable bike lights or lights specifically designed for cycling safety."
    },
    {
      keys: ['motorcycle', 'motorbike', 'moto'],
      reason: "Motorcycle gear is explicitly excluded. The benefit is for non-motorized bicycle commuting."
    },
    { 
      keys: ['citibike', 'citi'], 
      reason: "Citi Bike is not eligible. Only local Boston-area bike share services like Bluebikes and CargoB are covered." 
    },
    {
      keys: ['carrack', 'roofrack', 'trunkrack', 'hitchrack', 'vehiclerack'],
      reason: "Car-mounted bike racks are considered vehicle accessories rather than cycling equipment and are not eligible."
    }
  ];

  for (const rule of forbidden) {
    if (rule.keys.some(k => normalized.includes(k))) {
      return {
        status: EligibilityStatus.INELIGIBLE,
        itemName: "Non-Eligible Item",
        reasoning: rule.reason,
        recommendations: ["Review the Sustainable Transportation page for eligible equipment."],
        isReceiptDetected: false,
        estimatedCost: "N/A"
      };
    }
  }

  // 3. Positive Heuristics (General Keywords)
  for (const keyword of AUTO_ELIGIBLE_KEYWORDS) {
    if (normalized.includes(normalizeKey(keyword))) {
      return {
        status: EligibilityStatus.ELIGIBLE,
        itemName: keyword.charAt(0).toUpperCase() + keyword.slice(1),
        reasoning: `"${keyword}" is a standard piece of cycling equipment explicitly covered under the Harvard Bike Commuter Benefit.`,
        recommendations: ["Save your itemized receipt", "Log into the Jawnt portal to submit your claim"],
        isReceiptDetected: false,
        estimatedCost: "N/A"
      };
    }
  }
  return null;
};

const withRetry = async <T>(fn: () => Promise<T>, retries = 3, delay = 2000): Promise<T> => {
  try {
    return await fn();
  } catch (error: any) {
    const isRateLimit = error.message?.includes('429') || error.status === 429 || error.message?.includes('RESOURCE_EXHAUSTED');
    if (retries > 0 && isRateLimit) {
      await new Promise(resolve => setTimeout(resolve, delay));
      return withRetry(fn, retries - 1, delay * 2);
    }
    throw error;
  }
};

export const analyzeBikePurchase = async (
  input: string | { data: string; mimeType: string }
): Promise<AnalysisResult> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) throw new Error("API Key missing.");

  if (typeof input === 'string') {
    const key = normalizeKey(input);
    if (textCache.has(key)) return textCache.get(key)!;
    const hResult = checkHeuristics(input);
    if (hResult) {
      textCache.set(key, hResult);
      return hResult;
    }
  }

  const performAnalysis = async () => {
    const ai = new GoogleGenAI({ apiKey });
    const isImage = typeof input !== 'string';
    const urlRegex = /(https?:\/\/[^\s]+|www\.[^\s]+|[a-z0-9]+\.[a-z]{2,})/i;
    const needsSearch = !isImage && urlRegex.test(input);

    const contents = isImage ? 
      [{ inlineData: input }, { text: "Analyze this image for Harvard bike benefit eligibility. REMEMBER: Only bikes/frames are eligible from private parties. All other gear must be from a commercial retailer. If it's a part/accessory from an individual, it's INELIGIBLE." }] : 
      [{ text: `Evaluate this purchase for Harvard Bike Benefit: ${input}. REMEMBER: Only a bike/frame can be purchased from a private party. Gear/parts/apparel from individuals are INELIGIBLE.` }];

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: { parts: contents },
      config: {
        systemInstruction: SYSTEM_PROMPT,
        tools: needsSearch ? [{ googleSearch: {} }] : undefined,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            status: { type: Type.STRING },
            itemName: { type: Type.STRING },
            reasoning: { type: Type.STRING },
            recommendations: { type: Type.ARRAY, items: { type: Type.STRING } },
            isReceiptDetected: { type: Type.BOOLEAN },
            estimatedCost: { type: Type.STRING },
            followUpQuestions: { type: Type.ARRAY, items: { type: Type.STRING } }
          },
          required: ["status", "reasoning", "recommendations", "isReceiptDetected"]
        }
      },
    });

    let rawText = response.text || "";
    rawText = rawText.replace(/```json\n?/, '').replace(/\n?```/, '').trim();
    const result = JSON.parse(rawText) as AnalysisResult;

    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    if (groundingChunks) {
      const sources: GroundingSource[] = [];
      groundingChunks.forEach((c: any) => { if (c.web?.uri) sources.push({ uri: c.web.uri, title: c.web.title || "Reference" }); });
      if (sources.length > 0) result.groundingUrls = sources;
    }
    return result;
  };

  try {
    const result = await withRetry(performAnalysis);
    if (typeof input === 'string') textCache.set(normalizeKey(input), result);
    return result;
  } catch (error: any) {
    if (error.message?.includes('429') || error.message?.includes('RESOURCE_EXHAUSTED')) {
      throw new Error("The AI service is currently at capacity. Please wait a moment and try again.");
    }
    throw new Error(error.message || "Analysis failed.");
  }
};

import React, { useState } from 'react';
import { AnalysisResult, EligibilityStatus } from '../types';

interface ResultDisplayProps {
  result: AnalysisResult;
  onReset: () => void;
  onFollowUp: (question: string, customAnswer: string) => void;
}

const ResultDisplay: React.FC<ResultDisplayProps> = ({ result, onReset, onFollowUp }) => {
  const [answers, setAnswers] = useState<{ [key: number]: string }>({});

  const getStatusConfig = (status: EligibilityStatus) => {
    switch (status) {
      case EligibilityStatus.ELIGIBLE:
        return { icon: 'fa-check-circle', color: 'bg-emerald-500', textColor: 'text-emerald-950', label: 'PASSED' };
      case EligibilityStatus.INELIGIBLE:
        return { icon: 'fa-times-circle', color: 'bg-red-600', textColor: 'text-white', label: 'REJECTED' };
      default:
        return { icon: 'fa-circle-question', color: 'bg-amber-400', textColor: 'text-amber-950', label: 'ON THE FENCE' };
    }
  };

  const config = getStatusConfig(result.status);
  const showFollowUps = result.followUpQuestions && result.followUpQuestions.length > 0;

  // Stricter check for N/A cost or empty cost
  const hasValidCost = result.estimatedCost && 
    !['null', 'n/a', '', '0', 'none', 'unknown'].includes(result.estimatedCost.toLowerCase().replace(/[^a-z0-9]/g, ''));

  const hasGrounding = result.groundingUrls && result.groundingUrls.length > 0;

  const renderTextWithLinks = (text: string) => {
    const urlRegex = /(https?:\/\/[^\s]+)/g;
    const parts = text.split(urlRegex);
    return parts.map((part, i) => {
      if (part.match(urlRegex)) {
        return (
          <a key={i} href={part} target="_blank" rel="noopener noreferrer" className="text-blue-600 hover:text-blue-800 underline decoration-2 underline-offset-2 break-all">
            {part}
          </a>
        );
      }
      return <span key={i}>{part}</span>;
    });
  };

  const handleAnswerSubmit = (index: number) => {
    const q = result.followUpQuestions![index];
    const a = answers[index] || "Not provided";
    onFollowUp(q, a);
  };

  const handleQuickConfirm = (index: number) => {
    const q = result.followUpQuestions![index];
    onFollowUp(q, "Yes, this applies to my purchase.");
  };

  return (
    <div className="space-y-8 animate-in fade-in zoom-in-95 duration-500">
      <div className="bg-white border-4 border-black brutalist-shadow relative overflow-hidden">
        <div className="flex flex-col md:flex-row">
            <div className={`${config.color} border-b-4 md:border-b-0 md:border-r-4 border-black p-8 flex flex-col items-center justify-center md:min-w-[200px]`}>
                <div className="text-5xl mb-4 text-black opacity-20"><i className={`fas ${config.icon}`}></i></div>
                <div className={`text-3xl font-black ${config.textColor} tracking-tighter uppercase italic text-center leading-none`}>
                  {config.label}
                </div>
            </div>

            <div className="flex-grow p-8">
                <div className="flex justify-between items-start mb-6 border-b-2 border-dashed border-gray-200 pb-4">
                    <div className="flex-grow pr-4">
                        <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest block">Analysis Target</span>
                        <h3 className="text-2xl font-black text-black uppercase tracking-tight break-words">{result.itemName || 'Bike Purchase'}</h3>
                    </div>
                    {hasValidCost && (
                        <div className="bg-black text-white px-3 py-1 font-black text-sm italic h-fit shrink-0">
                          {result.estimatedCost}
                        </div>
                    )}
                </div>

                <div className="mb-6">
                    <p className="text-lg font-bold text-gray-800 leading-tight mb-6">{result.reasoning}</p>

                    {showFollowUps && (
                        <div className="mb-8 bg-black text-white p-6 border-4 border-black brutalist-shadow-sm">
                            <h4 className="text-xs font-black uppercase tracking-widest mb-4 flex items-center gap-2 text-amber-400">
                                <i className="fas fa-comment-dots"></i> Action Required to Finalize:
                            </h4>
                            <div className="space-y-6">
                                {result.followUpQuestions?.map((q, i) => (
                                    <div key={i} className="bg-gray-900 border-2 border-gray-800 p-4 transition-all">
                                        <div className="flex gap-3 items-start mb-4">
                                            <div className="bg-amber-400 text-black w-6 h-6 rounded-full flex items-center justify-center font-black text-xs shrink-0 mt-1">?</div>
                                            <p className="text-sm font-bold text-gray-100 leading-snug">{q}</p>
                                        </div>

                                        <div className="space-y-3">
                                            <textarea
                                              value={answers[i] || ''}
                                              onChange={(e) => setAnswers({...answers, [i]: e.target.value})}
                                              placeholder="Type your answer here..."
                                              className="w-full bg-black border-2 border-gray-700 p-3 text-white text-sm font-bold focus:border-amber-400 outline-none resize-none h-20"
                                            />
                                            <div className="flex flex-col sm:flex-row gap-3">
                                                <button 
                                                    onClick={() => handleAnswerSubmit(i)}
                                                    className="bg-amber-400 text-black px-4 py-2 font-black text-[10px] uppercase tracking-wider hover:bg-white transition-all brutalist-shadow-sm"
                                                >
                                                    Submit Answer
                                                </button>
                                                <button 
                                                    onClick={() => handleQuickConfirm(i)}
                                                    className="bg-transparent border-2 border-gray-700 text-gray-400 px-4 py-2 font-black text-[10px] uppercase tracking-wider hover:text-white hover:border-white transition-all"
                                                >
                                                    Quick Confirm (Yes)
                                                </button>
                                            </div>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>
                    )}

                    <div className="space-y-2 mb-6">
                        <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest block mb-1">Recommended Actions</span>
                        {result.recommendations.map((rec, i) => (
                            <div key={i} className="flex items-start gap-3 text-sm font-bold text-gray-600 bg-gray-50 p-3 border-l-4 border-black">
                                <i className="fas fa-arrow-right text-[10px] mt-1"></i>
                                <span className="leading-tight">{renderTextWithLinks(rec)}</span>
