import { trackSearch, trackPageView } from './services/telemetry';
import { AnalysisState } from './types';
import { EXAMPLE_PURCHASES } from './constants';

const App: React.FC = () => {
  const [state, setState] = useState<AnalysisState>({
    isAnalyzing: false,
    result: null,
    error: null,
  });
  const [inputText, setInputText] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    trackPageView('Home');
  }, []);

  const handleFollowUp = async (question: string, customAnswer: string) => {
    const context = `Context: The user previously asked about a bike purchase. 
Model Question: ${question}
User Answer: ${customAnswer}

Please re-evaluate eligibility based on this new information.`;

    setInputText(`Answering: ${question} -> ${customAnswer}`);
    setState({ ...state, isAnalyzing: true, result: null });
    try {
      const result = await analyzeBikePurchase(context);
      setState({ isAnalyzing: false, result, error: null });
      trackSearch(result.itemName || "Clarification", result.status);
    } catch (err: any) {
      setState({ isAnalyzing: false, error: err.message || 'Failed to re-analyze.' });
    }
  };

  const resizeImage = (file: File): Promise<{ data: string, mimeType: string }> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = (event) => {
        const img = new Image();
        img.src = event.target?.result as string;
        img.onload = () => {
          const canvas = document.createElement('canvas');
          const MAX_SIZE = 1200;
          let width = img.width;
          let height = img.height;
          if (width > height) {
            if (width > MAX_SIZE) { height *= MAX_SIZE / width; width = MAX_SIZE; }
          } else {
            if (height > MAX_SIZE) { width *= MAX_SIZE / height; height = MAX_SIZE; }
          }
          canvas.width = width;
          canvas.height = height;
          canvas.getContext('2d')?.drawImage(img, 0, 0, width, height);
          resolve({ data: canvas.toDataURL('image/jpeg', 0.8).split(',')[1], mimeType: 'image/jpeg' });
        };
        img.onerror = reject;
      };
      reader.onerror = reject;
    });
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    setState({ ...state, isAnalyzing: true, error: null });
    try {
      let payload;
      if (file.type.startsWith('image/')) {
        payload = await resizeImage(file);
      } else {
        const base64Data = await new Promise<string>((resolve) => {
          const reader = new FileReader();
          reader.onload = (e) => resolve(e.target?.result?.toString().split(',')[1] || "");
          reader.readAsDataURL(file);
        });
        payload = { data: base64Data, mimeType: file.type };
      }
      const result = await analyzeBikePurchase(payload);
      setState({ isAnalyzing: false, result, error: null });
      trackSearch(result.itemName || "Image Upload", result.status);
    } catch (err: any) {
      setState({ isAnalyzing: false, result: null, error: err.message || 'Analysis failed.' });
    }
  };

  const handleTextSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputText.trim()) return;
    setState({ ...state, isAnalyzing: true, error: null });
    try {
      const result = await analyzeBikePurchase(inputText);
      setState({ isAnalyzing: false, result, error: null });
      trackSearch(result.itemName || inputText, result.status);
    } catch (err: any) {
      setState({ isAnalyzing: false, error: err.message || 'Failed to analyze text.' });
    }
  };

  const randomExample = useMemo(() => {
    return EXAMPLE_PURCHASES[Math.floor(Math.random() * EXAMPLE_PURCHASES.length)];
  }, []);

  return (
    <div className="min-h-screen bg-[#f0f0f0] flex flex-col selection:bg-black selection:text-white">
      <Header />

      <main className="flex-grow max-w-4xl mx-auto w-full px-6 py-12">
        <div className="mb-16">
          <h2 className="text-6xl md:text-8xl font-black text-black mb-6 tracking-tighter leading-[0.9] uppercase italic">
            Eligibility Check
          </h2>
          <div className="flex flex-col md:flex-row md:items-center gap-4">
             <div className="h-2 w-24 bg-red-600"></div>
             <p className="text-black max-w-lg font-bold text-lg leading-snug">
               Scan receipts or describe your gear to determine eligibility for the bike benefit program.
             </p>
          </div>
        </div>

        {state.error && (
          <div className="mb-8 bg-red-600 text-white p-6 border-4 border-black brutalist-shadow-sm animate-in slide-in-from-top-4 duration-300">
            <div className="flex items-center gap-4">
              <i className="fas fa-circle-exclamation text-3xl"></i>
              <div className="flex-grow">
                <h4 className="font-black uppercase tracking-tight">System Notice</h4>
                <p className="text-sm font-bold opacity-90">{state.error}</p>
              </div>
              <button onClick={() => setState({ ...state, error: null })} className="bg-white text-black px-4 py-2 font-black text-xs uppercase">Dismiss</button>
            </div>
          </div>
        )}

        {state.result ? (
          <ResultDisplay 
            result={state.result} 
            onReset={() => setState({ ...state, result: null, error: null })} 
            onFollowUp={handleFollowUp}
          />
        ) : state.isAnalyzing ? (
          <div className="flex flex-col items-center justify-center py-24 text-center overflow-hidden">
            <div className="relative w-64 h-32 mb-16">
               {/* Landscape Elements */}
               <div className="absolute bottom-4 left-0 w-full h-1 bg-black/10"></div>
               <div className="absolute bottom-4 left-0 w-full h-[2px] overflow-hidden">
                  <div className="w-[300%] h-full bg-[repeating-linear-gradient(90deg,black,black_20px,transparent_20px,transparent_40px)] animate-[road-move_0.8s_infinite_linear]"></div>
               </div>

               {/* Whimsical Bouncing Bike */}
               <div className="absolute bottom-4 left-1/2 -translate-x-1/2 animate-[bike-travel_1.5s_infinite_ease-in-out]">
                  <svg viewBox="0 0 100 50" className="w-40 h-20 fill-none stroke-black stroke-[1.5]">
                    {/* Frame */}
                    <path d="M25 40 L45 40 L55 25 L35 15 L25 40" />
                    <path d="M45 40 L60 15" />
                    <path d="M55 25 L75 40" />

                    {/* Handlebars & Seat */}
                    <line x1="58" y1="15" x2="68" y2="15" strokeWidth="2" strokeLinecap="round" />
                    <line x1="32" y1="15" x2="40" y2="15" stroke="red" strokeWidth="3" strokeLinecap="round" />

                    {/* Front Wheel */}
                    <g className="animate-[wheel-spin_0.6s_infinite_linear] origin-[75px_40px]">
                      <circle cx="75" cy="40" r="9" />
                      <line x1="75" y1="31" x2="75" y2="49" opacity="0.4" />
                      <line x1="66" y1="40" x2="84" y2="40" opacity="0.4" />
                    </g>

                    {/* Back Wheel */}
                    <g className="animate-[wheel-spin_0.6s_infinite_linear] origin-[25px_40px]">
                      <circle cx="25" cy="40" r="9" />
                      <line x1="25" y1="31" x2="25" y2="49" opacity="0.4" />
                      <line x1="16" y1="40" x2="34" y2="40" opacity="0.4" />
                    </g>
                  </svg>
               </div>
            </div>

            <div className="space-y-4">
              <h3 className="text-4xl font-black text-black tracking-tighter uppercase italic">
                Pedaling through the fine print...
              </h3>
              <p className="text-[10px] text-gray-400 font-bold uppercase tracking-[0.5em] animate-pulse">
                Greasing the gears of bureaucracy
              </p>
            </div>

            <style>{`
              @keyframes road-move {
                from { transform: translateX(0); }
